#include <stdio.h>
#define MOD 1000000007
int main() {
    int T, n, k, i, ans;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &k);
        ans = 1;
        for (i = 1; i <= n; i++) {
            if (i <= n - k) {
                ans = (ans * (1 + (1LL << (i - 1)))) % MOD;
            } else {
                ans = (ans * (1LL << (n - i))) % MOD;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

